def sort_stack(stack):
    if not stack:
        return

    temp = stack.pop()

    sort_stack(stack)

    _insert_sorted(stack, temp)


def _insert_sorted(stack, element):
    if not stack or element >= stack[-1]:
        stack.append(element)
        return

    temp = stack.pop()
    _insert_sorted(stack, element)
    stack.append(temp)
